export type FoodType = '飼料' | '罐頭' | '零食';

export interface FoodDef {
  id: string;
  name: string;
  type: FoodType;
  caloriesPerGram: number; // kcal/g
  waterContentPercent: number; // % (0-100)
  order?: number; // Display order
  isDefault?: boolean; // Is this the default food for new days?
  defaultAmount?: number; // Default amount in grams to pre-fill
}

// Changed to string to allow intermediate values like "1元 ~ 50元"
export type UrineSize = string; 
export type StoolStatus = '正常' | '未大便' | '顆粒狀' | '稀便';

export interface FoodIntake {
  id: string;
  foodId: string;
  amount: number; // grams
}

export type WaterIntakeType = 'bowl' | 'direct' | 'evaporation';

export interface WaterIntake {
  id: string;
  type: WaterIntakeType;
  amount1: number; // Original for bowl, Amount for direct/evaporation
  amount2: number | null; // Leftover for bowl (null if not set yet), 0 for others
  evaporation?: number; // Deprecated: Kept for legacy records
}

export interface DailyRecord {
  id: string;
  date: string; // YYYY-MM-DD
  weight: number; // kg

  // Eating
  foodIntakes: FoodIntake[];

  // Drinking logic (Updated to list-based)
  waterIntakes: WaterIntake[];

  // Excretion
  urineSize: UrineSize;
  urineCount: number; 
  stoolStatus: StoolStatus;

  // Other
  notes: string;

  // Sync / Backup Metadata
  lastModified?: number; // Timestamp when record was last changed locally
  lastBackupTime?: number; // Timestamp when record was last successfully uploaded
}

// Helper interface for display
export interface DailySummary {
  date: string;
  totalCalories: number;
  totalWater: number;
  weight: number;
  urineSize: string;
  stoolStatus: string;
}

export interface AppSettings {
  targetWeight: number; // kg
  activityFactor: number; // 0.8 | 0.9 | 1.0 | 1.1 | 1.2
  defaultEvaporation: number; // ml
  notePresets?: string[];
  litterInterval?: number; // Days between litter changes
  medicationInterval?: number; // Days between medication
}

import { DailyRecord, FoodDef, WaterIntake, AppSettings } from '../types';
import { db } from './firebase';
import { collection, getDocs, setDoc, doc, deleteDoc, writeBatch, getDoc } from 'firebase/firestore';

// Initial data for seeding if DB is empty
// Updated: Merged '副食' into '零食'
const INITIAL_FOODS: FoodDef[] = [
  { id: 'f1', name: '雞肉燉菜', type: '罐頭', caloriesPerGram: 0.841, waterContentPercent: 85, order: 0 },
  { id: 'f2', name: '鮪魚燉菜', type: '罐頭', caloriesPerGram: 0.805, waterContentPercent: 84, order: 1 },
  // Set c/d stress as default with 30g to match previous hardcoded behavior for new databases
  { id: 'f3', name: 'c/d stress', type: '飼料', caloriesPerGram: 3.895, waterContentPercent: 8, order: 2, isDefault: true, defaultAmount: 30 },
  { id: 'f4', name: 'LP34', type: '飼料', caloriesPerGram: 3.872, waterContentPercent: 7, order: 3 },
  { id: 'f5', name: 'LP34W', type: '罐頭', caloriesPerGram: 0.816, waterContentPercent: 80.5, order: 4 },
  { id: 'f6', name: '豹放鬆', type: '零食', caloriesPerGram: 2.0, waterContentPercent: 60.5, order: 5 },
  { id: 'f7', name: '雞胸肉', type: '零食', caloriesPerGram: 1.19, waterContentPercent: 60, order: 6 },
];

const DEFAULT_NOTE_PRESETS = ['換砂', '點藥', '就醫', '健檢', '咳嗽', '嘔吐', '舔嘴唇', '精神差', '食慾差', '肚子翻攪'];

// Helper to remove undefined fields which Firestore doesn't like
const sanitizeForFirestore = <T extends object>(data: T): T => {
  const cleanData = { ...data };
  Object.keys(cleanData).forEach(key => {
    if ((cleanData as any)[key] === undefined) {
      delete (cleanData as any)[key];
    }
  });
  return cleanData;
};

// --- Settings Operations ---

export const fetchSettings = async (): Promise<AppSettings> => {
  try {
    const docRef = doc(db, "settings", "global");
    const docSnap = await getDoc(docRef);

    if (docSnap.exists()) {
      const data = docSnap.data() as AppSettings;
      // Ensure notePresets exists (migration)
      if (!data.notePresets || data.notePresets.length === 0) {
          data.notePresets = DEFAULT_NOTE_PRESETS;
      }
      return data;
    } else {
      // Default settings
      const defaultSettings: AppSettings = {
        targetWeight: 5.0,
        activityFactor: 1.0,
        defaultEvaporation: 0,
        notePresets: DEFAULT_NOTE_PRESETS,
        litterInterval: 14, // Default to 14 days
        medicationInterval: 30 // Default to 30 days
      };
      await setDoc(docRef, sanitizeForFirestore(defaultSettings));
      return defaultSettings;
    }
  } catch (error) {
    console.error("Error fetching settings:", error);
    // Return safe default if offline or error
    return {
        targetWeight: 5.0,
        activityFactor: 1.0,
        defaultEvaporation: 0,
        notePresets: DEFAULT_NOTE_PRESETS,
        litterInterval: 14,
        medicationInterval: 30
    };
  }
};

export const saveSettings = async (settings: AppSettings): Promise<void> => {
  try {
    const docRef = doc(db, "settings", "global");
    await setDoc(docRef, sanitizeForFirestore(settings));
  } catch (error) {
    console.error("Error saving settings:", error);
    throw error;
  }
};

// --- Food Operations ---

export const fetchFoods = async (): Promise<FoodDef[]> => {
  try {
    const querySnapshot = await getDocs(collection(db, "foods"));
    if (querySnapshot.empty) {
      // Seed initial data
      const batch = writeBatch(db);
      INITIAL_FOODS.forEach(f => {
        batch.set(doc(db, "foods", f.id), sanitizeForFirestore(f));
      });
      await batch.commit();
      return INITIAL_FOODS;
    }

    const foods: FoodDef[] = [];
    querySnapshot.forEach(doc => {
      foods.push(doc.data() as FoodDef);
    });
    return foods.sort((a, b) => (a.order ?? 0) - (b.order ?? 0));
  } catch (error) {
    console.error("Error fetching foods:", error);
    return [];
  }
};

export const saveFoodToRemote = async (food: FoodDef, allFoods?: FoodDef[]): Promise<void> => {
  try {
    await setDoc(doc(db, "foods", food.id), sanitizeForFirestore(food));
  } catch (error) {
    console.error("Error saving food:", error);
    throw error;
  }
};

export const deleteFoodFromRemote = async (id: string): Promise<void> => {
  try {
    await deleteDoc(doc(db, "foods", id));
  } catch (error) {
    console.error("Error deleting food:", error);
    throw error;
  }
};

export const saveFoodsOrderToRemote = async (foods: FoodDef[]): Promise<void> => {
  try {
    const batch = writeBatch(db);
    foods.forEach(f => {
      const ref = doc(db, "foods", f.id);
      batch.update(ref, { order: f.order });
    });
    await batch.commit();
  } catch (error) {
    console.error("Error updating food order:", error);
    throw error;
  }
};

// --- Record Operations ---

export const fetchRecords = async (): Promise<DailyRecord[]> => {
  try {
    const querySnapshot = await getDocs(collection(db, "records"));
    const records: DailyRecord[] = [];
    querySnapshot.forEach(doc => {
      records.push(doc.data() as DailyRecord);
    });
    return records;
  } catch (error) {
    console.error("Error fetching records:", error);
    return [];
  }
};

export const saveRecordToRemote = async (record: DailyRecord): Promise<void> => {
  try {
    // Automatically update lastModified timestamp
    const updatedRecord = {
        ...record,
        lastModified: Date.now()
    };
    await setDoc(doc(db, "records", record.id), sanitizeForFirestore(updatedRecord));
  } catch (error) {
    console.error("Error saving record:", error);
    throw error;
  }
};

// Batch update to mark records as backed up
export const markRecordsAsBackedUp = async (recordIds: string[]): Promise<void> => {
    try {
        const batch = writeBatch(db);
        const now = Date.now();
        recordIds.forEach(id => {
            const ref = doc(db, "records", id);
            batch.update(ref, { lastBackupTime: now });
        });
        await batch.commit();
    } catch (error) {
        console.error("Error marking records as backed up:", error);
        throw error;
    }
};

export const deleteRecordFromRemote = async (id: string): Promise<void> => {
  try {
    await deleteDoc(doc(db, "records", id));
  } catch (error) {
    console.error("Error deleting record:", error);
    throw error;
  }
};

// --- Calculation Helper ---

export const calculateDailyStats = (record: DailyRecord, foods: FoodDef[]) => {
  let totalCalories = 0;
  let sideCalories = 0;
  let foodWater = 0;
  let drinkWater = 0;

  // Food Stats
  if (record.foodIntakes) {
    record.foodIntakes.forEach(intake => {
      const food = foods.find(f => f.id === intake.foodId);
      if (food) {
        const cals = intake.amount * food.caloriesPerGram;
        totalCalories += cals;

        // Handle legacy '副食' by treating it as '零食'
        // Type casting to string to safely check legacy types
        const typeStr = food.type as string;
        if (typeStr === '零食' || typeStr === '副食') {
          sideCalories += cals;
        }

        const water = intake.amount * (food.waterContentPercent / 100);
        foodWater += water;
      }
    });
  }

  // Water Stats
  if (record.waterIntakes) {
    record.waterIntakes.forEach(w => {
       if (w.type === 'bowl') {
          if (w.amount2 !== null && w.amount2 !== undefined) {
             const evap = w.evaporation || 0;
             const consumed = Math.max(0, w.amount1 - w.amount2 - evap);
             drinkWater += consumed;
          }
       } else if (w.type === 'direct') {
          drinkWater += w.amount1;
       } else if (w.type === 'evaporation') {
          drinkWater -= w.amount1;
       }
    });
  }

  return {
    totalCalories,
    sideCalories,
    foodWater,
    totalWater: foodWater + drinkWater,
    drinkWater
  };
};

import React, { useState, useMemo, useEffect } from 'react';
import { DailyRecord, FoodDef, AppSettings } from '../types';
import { calculateDailyStats, markRecordsAsBackedUp } from '../services/storage';
import { Calendar as CalendarIcon, AlertTriangle, Scale, X, CloudUpload, Cookie, ChevronLeft, ChevronRight, Flame, Droplet, Loader2, Check } from 'lucide-react';

interface Props {
  records: DailyRecord[];
  foods: FoodDef[];
  settings: AppSettings;
  onSelectDate: (date: string) => void;
}

const URINE_ANCHORS = ['1元', '50元', '半拳', '一拳', '巨大'];
const WEEK_DAYS = ['日', '一', '二', '三', '四', '五', '六'];
const GOOGLE_SCRIPT_URL = "https://script.google.com/macros/s/AKfycbx9LlsY_4-J-7ZVDxDXQEMdV6RnDghlVK8YZXMtJlk1l8KBnmbhnEtAI1frsqD8NKWe/exec";

const HistoryView: React.FC<Props> = ({ records, foods, settings, onSelectDate }) => {
  // --- Export/Backup State ---
  const [showBackupModal, setShowBackupModal] = useState(false);
  const [backupStartDate, setBackupStartDate] = useState('');
  const [backupEndDate, setBackupEndDate] = useState('');
  const [isUploading, setIsUploading] = useState(false);
  const [uploadSuccess, setUploadSuccess] = useState(false);

  // --- Calendar State ---
  const [currentMonth, setCurrentMonth] = useState(new Date());
  // Default selected date to today or the latest record date
  const [selectedDate, setSelectedDate] = useState<string>('');

  // Initialize selectedDate on load
  useEffect(() => {
    const today = new Date();
    const offset = today.getTimezoneOffset();
    const localToday = new Date(today.getTime() - (offset * 60 * 1000)).toISOString().split('T')[0];

    if (!selectedDate) {
        setSelectedDate(localToday);
    }
  }, []);

  // --- Helpers ---

  const getUrineValue = (label: string): number => {
    const exactIndex = URINE_ANCHORS.indexOf(label);
    if (exactIndex !== -1) return exactIndex;

    if (label.includes(' ~ ')) {
      const parts = label.split(' ~ ');
      const startIdx = URINE_ANCHORS.indexOf(parts[0]);
      if (startIdx !== -1) return startIdx + 0.5;
    }
    return 2; 
  };

  const formatDateString = (date: Date): string => {
    const offset = date.getTimezoneOffset();
    const local = new Date(date.getTime() - (offset * 60 * 1000));
    return local.toISOString().split('T')[0];
  };

  const getDaysInMonth = (date: Date) => {
    const year = date.getFullYear();
    const month = date.getMonth();
    const days = new Date(year, month + 1, 0).getDate();
    const firstDay = new Date(year, month, 1).getDay();
    return { days, firstDay, year, month };
  };

  const changeMonth = (delta: number) => {
    const newDate = new Date(currentMonth);
    newDate.setMonth(newDate.getMonth() + delta);
    setCurrentMonth(newDate);
  };

  // Build a map of date -> active weight
  const dailyWeightMap = useMemo(() => {
    const map = new Map<string, number>();
    const sortedRecords = [...records].sort((a, b) => a.date.localeCompare(b.date));

    let lastKnownWeight = 5.0;

    sortedRecords.forEach(r => {
        if (r.weight > 0) {
            lastKnownWeight = r.weight;
        }
        map.set(r.date, lastKnownWeight);
    });

    return map;
  }, [records]);

  // Build a map of date -> days since last litter change
  const dailyLitterAgeMap = useMemo(() => {
    const map = new Map<string, number>();
    const sortedRecords = [...records].sort((a, b) => a.date.localeCompare(b.date));

    let lastLitterDate: string | null = null;

    sortedRecords.forEach(r => {
        const hasLitterChange = r.notes && r.notes.includes('換砂');
        if (hasLitterChange) {
            lastLitterDate = r.date;
            map.set(r.date, 0);
        } else if (lastLitterDate) {
            const d1 = new Date(r.date);
            const d2 = new Date(lastLitterDate);
            const diffTime = Math.abs(d1.getTime() - d2.getTime());
            const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
            map.set(r.date, diffDays);
        } else {
            map.set(r.date, -1);
        }
    });

    return map;
  }, [records]);

  // Build a map of date -> days since last medication
  const dailyMedicationAgeMap = useMemo(() => {
    const map = new Map<string, number>();
    const sortedRecords = [...records].sort((a, b) => a.date.localeCompare(b.date));

    let lastMedDate: string | null = null;

    sortedRecords.forEach(r => {
        const hasMedication = r.notes && r.notes.includes('點藥');
        if (hasMedication) {
            lastMedDate = r.date;
            map.set(r.date, 0);
        } else if (lastMedDate) {
            const d1 = new Date(r.date);
            const d2 = new Date(lastMedDate);
            const diffTime = Math.abs(d1.getTime() - d2.getTime());
            const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
            map.set(r.date, diffDays);
        } else {
            map.set(r.date, -1);
        }
    });

    return map;
  }, [records]);

  const indicatorsMap = useMemo(() => {
    const map: Record<string, { pink: boolean, green: boolean, yellow: boolean, orange: boolean, blue: boolean }> = {};

    records.forEach(r => {
        const stats = calculateDailyStats(r, foods);
        const sideRatio = stats.totalCalories > 0 ? (stats.sideCalories / stats.totalCalories) : 0;
        const urineVal = getUrineValue(r.urineSize);

        const historicalWeight = dailyWeightMap.get(r.date) || 5.0;
        const historicalWaterGoal = historicalWeight * 40;

        map[r.date] = {
            pink: stats.totalWater < historicalWaterGoal,
            green: urineVal <= 1.5,
            yellow: sideRatio > 0.1,
            orange: r.stoolStatus !== '正常',
            blue: !!r.notes
        };
    });
    return map;
  }, [records, foods, dailyWeightMap]);

  const displayedRecords = useMemo(() => {
    if (!selectedDate) return [];

    const end = new Date(selectedDate);
    const start = new Date(end);
    start.setDate(end.getDate() - 6);

    const startStr = formatDateString(start);
    const endStr = formatDateString(end);

    return records
      .filter(r => r.date >= startStr && r.date <= endStr)
      .sort((a, b) => b.date.localeCompare(a.date));
  }, [records, selectedDate]);


  // --- Cloud Backup Logic ---

  const handleOpenBackup = () => {
    const today = new Date();
    const firstDay = new Date(today.getFullYear(), today.getMonth(), 1);
    setBackupStartDate(formatDateString(firstDay));
    setBackupEndDate(formatDateString(today));
    setShowBackupModal(true);
    setUploadSuccess(false);
  };

  // Prepare records for backup and detect sync status
  const pendingBackupRecords = useMemo(() => {
      if (!backupStartDate || !backupEndDate) return [];

      const inRange = records.filter(r => r.date >= backupStartDate && r.date <= backupEndDate);

      // Filter for "Dirty" records: No backup time OR lastModified is newer than backup time
      // If lastModified is missing (legacy data), treat as modified if not backed up
      return inRange.filter(r => {
          if (!r.lastBackupTime) return true;
          // If we have a backup time, but lastModified is newer (or undefined/legacy assumed modified?)
          // Actually, if legacy records don't have lastModified, we should assume they need backup if !lastBackupTime.
          // If they have lastBackupTime, they are fine.
          // If user edits legacy record, saveRecordToRemote adds lastModified.

          const modTime = r.lastModified || 0;
          return modTime > r.lastBackupTime;
      });
  }, [records, backupStartDate, backupEndDate]);

  const handleCloudUpload = async () => {
    const filtered = records.filter(r => r.date >= backupStartDate && r.date <= backupEndDate);
    filtered.sort((a, b) => a.date.localeCompare(b.date));

    if (filtered.length === 0) {
        alert('選定的期間內沒有紀錄可上傳');
        return;
    }

    setIsUploading(true);

    try {
        const payload = filtered.map(r => {
            const stats = calculateDailyStats(r, foods);

            // Calculate Snack Info
            const totalCals = stats.totalCalories;
            const sideCals = stats.sideCalories;
            const ratio = totalCals > 0 ? (sideCals / totalCals * 100).toFixed(0) : "0";

            // Get unique snack names
            const snackNames = new Set<string>();
            if (r.foodIntakes) {
                r.foodIntakes.forEach(i => {
                    const f = foods.find(food => food.id === i.foodId);
                    if (f && (f.type === '零食' || f.type === '副食' as any)) {
                        snackNames.add(f.name);
                    }
                });
            }
            const namesStr = Array.from(snackNames).join('、');
            const snackInfoStr = namesStr ? `${ratio}%, ${namesStr}` : `${ratio}%`;

            return {
                date: r.date,
                weight: r.weight > 0 ? r.weight : "",
                totalCalories: parseFloat(stats.totalCalories.toFixed(1)),
                snackInfo: snackInfoStr,
                totalWater: parseFloat(stats.totalWater.toFixed(1)),
                urineSize: r.urineSize,
                stoolStatus: r.stoolStatus,
                notes: r.notes || ""
            };
        });

        // Use 'no-cors' mode as standard Google Apps Script Web App endpoints often have CORS issues
        // However, 'no-cors' prevents reading the response.
        // We will try standard POST assuming the provided GAS code handles OPTIONS/CORS.
        const response = await fetch(GOOGLE_SCRIPT_URL, {
            method: 'POST',
            headers: {
                'Content-Type': 'text/plain;charset=utf-8', // Plain text avoids preflight in some cases, but GAS handles JSON string in body
            },
            body: JSON.stringify(payload)
        });

        const result = await response.json();

        if (result.result === 'success') {
            // Update local state to mark these records as backed up
            const idsToUpdate = filtered.map(r => r.id);
            await markRecordsAsBackedUp(idsToUpdate);

            // Manually update local records state to reflect backup immediately without reload
            const now = Date.now();
            // Note: In a real app we might reload from DB or update parent state via prop callback
            // Here, HistoryView receives records as prop, so we rely on parent update or refresh.
            // But since 'markRecordsAsBackedUp' updates Firestore, the next app load is fine.
            // To show immediate feedback, we set success state.
            setUploadSuccess(true);
            setTimeout(() => {
                setShowBackupModal(false);
                setUploadSuccess(false);
                // Trigger a page reload or data refresh if possible, 
                // but simpler to just let user see "Pending" count go to 0 next time they open modal
                // if we could update parent state. For now, simple alert or auto-close.
                window.location.reload(); // Simple way to refresh data and clear "Pending" status
            }, 1500);
        } else {
            throw new Error(result.error || 'Upload failed');
        }

    } catch (error) {
        console.error("Upload failed", error);
        alert('上傳失敗，請檢查網路連線或稍後再試。');
    } finally {
        setIsUploading(false);
    }
  };


  const renderCalendarDays = () => {
    const { days, firstDay, year, month } = getDaysInMonth(currentMonth);
    const daysArray = [];

    for (let i = 0; i < firstDay; i++) {
      daysArray.push(<div key={`empty-${i}`} className="h-14"></div>);
