                                    </div>
                                )}
                                {isMedicationOverdue && (
                                    <div className="text-[#DA6C6C] text-[10px] flex items-center gap-1 bg-red-50 px-2 py-0.5 rounded-full border border-red-100 animate-pulse font-bold">
