                                        <div className="flex gap-2 h-[18px] items-center">
                                            {calorieRows.map((item, idx) => (
                                                <div key={idx} className={`flex-1 text-center text-[10px] whitespace-nowrap ${item.isWarn ? "text-[#DA6C6C] font-bold" : "text-[#A67B7B]"}`}>
                                                    {item.weight} g
