export const saveFoodsOrderToRemote = async (foods: FoodDef[]): Promise<void> => {
  try {
    const batch = writeBatch(db);
    foods.forEach(f => {
      const ref = doc(db, "foods", f.id);
      batch.update(ref, { order: f.order });
    });
    await batch.commit();
