      // Save current state on blur
      if (JSON.stringify(localSettings) !== JSON.stringify(settings)) {
         saveSettingsDirectly(localSettings);
      }
  };

  const visibleFoods = selectedDbType 
    ? localFoods.filter(f => f.type === selectedDbType)
    : [];

