                </div>
           )}

           {/* List Display */}
           {!selectedDbType ? (
               <div className="text-center py-12 text-slate-400 bg-white rounded-xl border border-dashed border-slate-200">
                   <Database size={32} className="mx-auto mb-2 opacity-50" />
                   <p>請點擊上方按鈕選擇類別以檢視內容</p>
               </div>
           ) : visibleFoods.length === 0 ? (
               <div className="text-center py-12 text-slate-400 bg-white rounded-xl border border-dashed border-slate-200">
                   此類別尚未建立資料
