                        {/* Order Controls for Mobile */}
                        <div className="flex flex-col gap-1 md:hidden">
                            <button 
                                type="button"
                                onClick={(e) => {
                                    e.preventDefault();
                                    e.stopPropagation();
                                    moveItem(index, 'up');
