                                className="p-2 -m-1 text-slate-400 hover:text-[#6E96B8] disabled:opacity-20 active:scale-90 transition-transform"
                            >
                                <ArrowUp size={16} />
                            </button>
                            <button 
                                type="button"
                                onClick={(e) => {
                                    e.preventDefault();
                                    e.stopPropagation();
                                    moveItem(index, 'down');
